import React, { useState, useRef, useEffect } from "react";
import axios from 'axios'
import { useNavigate } from "react-router-dom";
const Journal = ({ editEntryId, onSaveComplete }) => {
  const navigate=useNavigate();
  const [title, setTitle] = useState("");
  const [date, setDate] = useState("");
  const [entry, setEntry] = useState("");
  const [analysisResult, setAnalysisResult] = useState("");
  const [currentId, setCurrentId] = useState(null);

  const textareaRef = useRef();

  useEffect(() => {
    if (editEntryId) {
      const savedEntries = JSON.parse(localStorage.getItem("journalEntries")) || [];
      const toEdit = savedEntries.find((e) => e.id === editEntryId);
      if (toEdit) {
        setTitle(toEdit.title || "");
        setDate(toEdit.date || "");
        setEntry(toEdit.entry || "");
        setAnalysisResult(toEdit.analysis || "");
        setCurrentId(toEdit.id);
      }
    }
  }, [editEntryId]);


  async function onEdit(id) {
    navigate(`/journal/${id}`);
    const updatedEntry = { title, date, journalNote: entry }
    const EditEntry = await axios.put(`api/journal/updateJournal/${id}`, { updatedEntry },
      {
        headers: {
          'Authorization': "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IjY4N2U3Y2QxNjdlYzBhMjRkYzg5YmM4MCIsImVtYWlsIjoiYWRtaW5AZ21haWwuY29tIiwiaWF0IjoxNzUzMTgyNTQ1fQ.7xkH-XSWImqVRBWBz66UkPE0cITAupPVl6Gyvo_KY0Y"
        }
      })
  }

  function autoResizeTextarea() {
    const textarea = textareaRef.current;
    if (textarea) {
      textarea.style.height = "auto";
      textarea.style.height = textarea.scrollHeight + "px";
    }
  }

  const handleAdd = async () => {
    if (!entry.trim()) {
      alert("Please write something before adding.");
      return;
    }
    const newEntry = {
      title,
      date,
      journalNote: entry,
    };
    const addingEntry = await axios.post('/api/journal/addJournal',
      newEntry, {
      headers: {
        'Authorization': "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IjY4N2U3Y2QxNjdlYzBhMjRkYzg5YmM4MCIsImVtYWlsIjoiYWRtaW5AZ21haWwuY29tIiwiaWF0IjoxNzUzMTgyNTQ1fQ.7xkH-XSWImqVRBWBz66UkPE0cITAupPVl6Gyvo_KY0Y"
      }
    })
  };

  // const handleAdd = () => {
  //   if (!entry.trim()) {
  //     alert("Please write something before adding.");
  //     return;
  //   }
  //   const savedEntries = JSON.parse(localStorage.getItem("journalEntries")) || [];
  //   const newEntry = {
  //     title,
  //     date,
  //     entry,
  //     analysis: analysisResult || null,
  //     analyzed: !!analysisResult,
  //   };

  //   if (currentId) {
  //     const updated = savedEntries.map((e) => (e.id === currentId ? newEntry : e));
  //     localStorage.setItem("journalEntries", JSON.stringify(updated));
  //   } else {
  //     localStorage.setItem("journalEntries", JSON.stringify([...savedEntries, newEntry]));
  //     setCurrentId(newEntry.id);
  //   }
  //   alert("Entry saved.");
  //   if (onSaveComplete) onSaveComplete();
  // };

  const handleAnalyze = async () => {
    if (!entry.trim()) {
      alert("Write something to analyze.");
      return;
    }

    try {
      const res = await fetch("http://localhost:5001/api/ai/analyze", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text: entry }),
      });
      const data = await res.json();

      if (data.all_scores && data.all_scores.length) {
        const topEmotions = data.all_scores
          .sort((a, b) => b.score - a.score)
          .slice(0, 3)
          .map((e) => `${e.label} (${(e.score * 100).toFixed(1)}%)`)
          .join(", ");

        const analysisText = `Top Emotions: ${topEmotions}`;
        setAnalysisResult(analysisText);

        if (currentId) {
          const savedEntries = JSON.parse(localStorage.getItem("journalEntries")) || [];
          const updatedEntries = savedEntries.map((e) =>
            e.id === currentId ? { ...e, analysis: analysisText, analyzed: true } : e
          );
          localStorage.setItem("journalEntries", JSON.stringify(updatedEntries));
          alert("Analysis saved with entry.");
        } else {
          alert("Analysis complete (not saved because entry not added yet).");
        }
      } else if (data.error) {
        setAnalysisResult(`Emotion analysis error: ${data.error}`);
      } else {
        setAnalysisResult("Emotion analysis failed. Try again.");
      }
    } catch (error) {
      console.error("Error analyzing entry:", error);
      setAnalysisResult("Error analyzing entry. Check console.");
    }
  };

  return (
    <div className="journal-page">
      <h1 className="journal-heading">{currentId ? "Edit Journal Entry" : "New Journal Entry"}</h1>
      <div className="journal-header">
        <input
          className="journal-title"
          placeholder="Title (optional)"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
        />
        <input
          className="journal-date"
          placeholder="mm/dd/yyyy"
          value={date}
          onChange={(e) => setDate(e.target.value)}
        />
      </div>

      <div className="journal-body">
        <textarea
          ref={textareaRef}
          className="journal-entry"
          placeholder="Write your journal entry here..."
          value={entry}
          onChange={(e) => {
            setEntry(e.target.value);
            autoResizeTextarea();
          }}
        />
      </div>

      <div className="journal-footer">
        <button onClick={handleAdd} className="journal-analyze" style={{ marginRight: "1rem" }}>
          {currentId ? "Save" : "Add"}
        </button>
        <button onClick={handleAnalyze} className="journal-analyze">
          Analyze
        </button>
      </div>

      {analysisResult && (
        <div
          style={{
            marginTop: "1rem",
            fontSize: "1.2rem",
            fontFamily: "'Cedarville Cursive', cursive",
            color: "var(--text)",
          }}
        >
          {analysisResult}
        </div>
      )}
      <Stylesheet />
    </div>
  );
};

const Stylesheet = () => {
  return (
    <style>{`
      .journal-page {
        font-family: 'Cedarville Cursive', cursive;
        color: var(--text);
        display: flex;
        justify-content: center;
        flex-direction: column;
        align-items: center;
        padding: 1rem;
      }

      .journal-heading {
        font-size: 2.5rem;
        text-align: center;
        margin-bottom: 1rem;
      }

      .journal-header {
        display: flex;
        flex-wrap: wrap;
        justify-content: center;
        gap: 1rem;
        width: 100%;
        max-width: 900px;
        margin-bottom: 1rem;
      }

      .journal-title,
      .journal-date {
        background-color: var(--secondary-color);
        border: none;
        padding: 10px;
        border-radius: 5px;
        font-size: 1.1rem;
        color: var(--text);
        font-family: 'Cedarville Cursive', cursive;
        flex: 1 1 200px;
        min-width: 150px;
      }

      .journal-body {
        margin-top: 1rem;
        margin-bottom: 2rem;
        width: 100%;
        display: flex;
        justify-content: center;
      }

      .journal-entry {
        width: 100%;
        max-width: 900px;
        min-height: 300px;
        background-color: var(--secondary-color);
        border: none;
        padding: 15px;
        border-radius: 5px;
        font-size: 1.1rem;
        font-family: 'Cedarville Cursive', cursive;
        color: var(--text);
        resize: vertical;
        outline: none;
        box-sizing: border-box;
        scrollbar-width: thin;
        scrollbar-color: var(--secondary-color) var(--text);
      }

      .journal-footer {
        display: flex;
        justify-content: center;
        width: 100%;
        gap:5%;
      }

      .journal-analyze {
        background-color: var(--button-color);
        border: none;
        padding: 10px 20px;
        border-radius: 5px;
        font-size: 1.3rem;
        color: var(--bg-parchment);
        font-family: 'Cedarville Cursive', cursive;
        cursor: pointer;
      }

      .journal-entry::-webkit-scrollbar {
        width: 12px;
      }

      .journal-entry::-webkit-scrollbar-track {
        background: var(--text);
      }

      .journal-entry::-webkit-scrollbar-thumb {
        background-color: var(--secondary-color);
        border-radius: 10px;
        width: 8px;
      }

      .journal-title::placeholder,
      .journal-date::placeholder,
      .journal-entry::placeholder {
        color: var(--text);
        opacity: 1;
      }

      @media (max-width: 768px) {
        .journal-heading {
          font-size: 2rem;
        }

        .journal-title,
        .journal-date {
          font-size: 1rem;
        }

        .journal-entry {
          font-size: 1rem;
        }

        .journal-analyze {
          font-size: 1.1rem;
          width: 100%;
          max-width: 200px;
        }
      }

      @media (max-width: 480px) {
        .journal-heading {
          font-size: 1.7rem;
        }

        .journal-title,
        .journal-date {
          width: 100%;
          font-size: 0.95rem;
        }

        .journal-entry {
          font-size: 0.95rem;
        }

        .journal-analyze {
          font-size: 1rem;
          padding: 10px;
        }
      }
    `}</style>
  );
};


export default Journal;


// when user click on journal card then it needs to show full on journal page with buttons save,analyze
// each journal card should also show analyzed or not
// after clicking on analyze it needs to show results on that journal page only parallaly saving the results for dashboard

